/** biome-ignore-all lint/suspicious/noCommentText: TypeScript directive comments needed for component */
import { SourceFrequency } from '@domain/entry';
import { formatCurrency } from '@ui/utils';
import { formatDate } from '@ui/utils/formatDate';
import { clsx } from 'clsx';
import currency from 'currency.js';
import { MouseEvent, useCallback, useContext, useMemo } from 'react';
import { useFormContext } from 'react-hook-form';
import { useEventSelectedTicketContext } from '../../ActionPageView/EventPageLayout/hooks';
import { Button } from '../Button';
import { FuturePledgeContext } from '../DonationSelector/components/FuturePledgeBanner';
import { Label } from '../Label';

type Props = {
  actionButtonBgColor?: string;
  actionButtonHoverBgColor?: string;
  actionButtonText?: string | null;
  actionButtonTextColor?: string;
  className?: string;
  customerCoveredFees?: boolean;
  donationAmount: number;
  form?: string;
  futurePledgeDate?: Date;
  isDisabled?: boolean;
  isLoading?: boolean;
  onClick?: (e: MouseEvent<HTMLButtonElement>) => unknown;
  selectedFrequency?: SourceFrequency | null;
  showFrequency?: boolean;
  totalAmount: number;
};

export const ActionPageSubmitButton = ({
  actionButtonBgColor,
  actionButtonHoverBgColor,
  actionButtonText,
  actionButtonTextColor,
  className,
  customerCoveredFees = false,
  donationAmount,
  form,
  futurePledgeDate,
  isDisabled,
  isLoading = false,
  onClick,
  selectedFrequency,
  showFrequency = true,
  totalAmount,
}: Props) => {
  const { trigger, watch } = useFormContext();
  const { totalTicketCount } = useEventSelectedTicketContext();

  const hasTicketsOnly = totalTicketCount > 0 && !donationAmount;
  const hasTicketsAndDonation = totalTicketCount > 0 && donationAmount;
  const promoCodeDiscount = watch('promoCodeDiscount');

  const totalAmt = useMemo(() => {
    if (!totalAmount) {
      return undefined;
    }

    const value = currency(totalAmount, {
      fromCents: true,
    });

    return formatCurrency(value.intValue, {
      hideDecimal: value.intValue === 0 || value.intValue.toString().slice(-2) === '00',
    });
  }, [totalAmount]);

  const buttonText = useMemo(() => {
    const providedButtonText = actionButtonText ?? undefined;
    const fallbackCheckoutText = 'Checkout';

    if (hasTicketsOnly || hasTicketsAndDonation || !!promoCodeDiscount) {
      return providedButtonText || fallbackCheckoutText;
    }

    if (donationAmount) {
      const baseText = providedButtonText || 'Donate';
      const amountText =
        totalAmt ??
        formatCurrency(donationAmount, {
          hideDecimal: donationAmount === 0 || donationAmount.toString().slice(-2) === '00',
        });
      const feesSuffix = customerCoveredFees ? ' + fees' : '';
      const frequencyLabel = selectedFrequency
        ? selectedFrequency.charAt(0).toUpperCase() + selectedFrequency.slice(1)
        : null;
      const shouldShowFrequency = showFrequency && frequencyLabel;

      if (shouldShowFrequency) {
        return `${baseText} ${amountText}${feesSuffix} - ${frequencyLabel.toLowerCase()}`;
      }

      return `${baseText} ${amountText}${feesSuffix}`;
    }

    return providedButtonText || fallbackCheckoutText;
  }, [
    actionButtonText,
    hasTicketsOnly,
    hasTicketsAndDonation,
    promoCodeDiscount,
    donationAmount,
    totalAmt,
    showFrequency,
    customerCoveredFees,
    selectedFrequency,
  ]);

  const { highlight: highlightFuturePledge } = useContext(FuturePledgeContext);

  const buttonClasses = clsx('mt-8 w-full text-[18px] font-semibold', className && className, {
    '!cursor-default opacity-[0.4] shadow-none': isDisabled,
    'rounded-b-none': hasTicketsOnly || hasTicketsAndDonation || futurePledgeDate,
  });
  const futurePledgeClasses = clsx(
    'w-full rounded-b-lg rounded-t-none border-none group-hover:!bg-[--label-hover-bg-color]',
    className && className
  );
  const totalLabelClasses = clsx(
    'relative w-full rounded-b-lg pt-2 text-center group-hover:!text-[--label-hover-bg-color]',
    {
      '!rounded-b-none': futurePledgeDate,
      'pb-2': !futurePledgeDate,
    }
  );

  const handleDisabledClick = useCallback(
    (e) => {
      if (isDisabled) {
        e.preventDefault();
        trigger();
      }
    },
    [isDisabled, trigger]
  );

  return (
    <>
      <Button
        className={buttonClasses}
        form={form}
        isLoading={isLoading}
        onClick={isDisabled ? handleDisabledClick : onClick}
        size="lg"
        style={{
          // CSS hack: use variables for hover states (since Tailwind can't do dynamic classes)
          '--ap-btn-bg-color': actionButtonBgColor ?? '#28c290',
          '--ap-btn-hover-bg-color': actionButtonHoverBgColor ?? '#14AE7C',
          '--ap-btn-text-color':
            actionButtonTextColor === 'neutral.0' ? '#fff' : (actionButtonTextColor ?? '#fff'),
        }}
        type={form ? 'submit' : 'button'}
        variant="donationAmount"
      >
        {buttonText}
      </Button>

      {hasTicketsOnly || hasTicketsAndDonation ? (
        <Label
          className={totalLabelClasses}
          style={{
            '--label-hover-bg-color': actionButtonHoverBgColor
              ? `${actionButtonHoverBgColor}20`
              : '#14AE7C',
            backgroundColor: actionButtonBgColor ? `${actionButtonBgColor}20` : '#fff',
            color: actionButtonBgColor ?? '#28c290',
          }}
          variant="medium"
        >
          Today&apos;s Total Charge {promoCodeDiscount ? 'after discounts' : ''}:{' '}
          {formatCurrency(totalAmount, {
            hideDecimal: totalAmount === 0 || totalAmount.toString().slice(-2) === '00',
          })}
        </Label>
      ) : null}

      {futurePledgeDate && (
        <Button
          className={futurePledgeClasses}
          onClick={() => highlightFuturePledge()}
          style={{
            '--label-hover-bg-color': actionButtonHoverBgColor
              ? `${actionButtonHoverBgColor}20`
              : '#14AE7C',
          }}
          variant="unstyled"
        >
          <Label
            className="relative w-full rounded-b-lg p-2 text-center"
            style={{
              backgroundColor: actionButtonBgColor ? `${actionButtonBgColor}20` : '#fff',
              color: actionButtonBgColor ?? '#28c290',
            }}
            variant="medium"
          >
            Additional charge of{' '}
            {formatCurrency(donationAmount, {
              hideDecimal: donationAmount === 0 || donationAmount.toString().slice(-2) === '00',
            })}{' '}
            scheduled for {formatDate(futurePledgeDate, 'MM/dd')}
          </Label>
        </Button>
      )}
    </>
  );
};
